#define BLOCK_SIZE 16

__kernel void hotspot(
    const int num_iterations,
    const __global float* power,
    const __global float* temp_in,
    __global float* temp_out,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    const float Cap_1 = step / Cap;
    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;
    const float amb_temp = 80.0f;

    int block_id_x = get_block_id(0);
    int block_id_y = get_block_id(1);

    int smallBlockCol = BLOCK_SIZE - borderCols;
    int smallBlockRow = BLOCK_SIZE - borderRows;

    int start_col = block_id_x * smallBlockCol;
    int start_row = block_id_y * smallBlockRow;

    int local_col = get_local_id(0);
    int local_row = get_local_id(1);

    int c = start_col + local_col;
    int r = start_row + local_row;

    if (c >= col || r >= row) return;

    int idx = r * col + c;

    float current_temp = temp_in[idx];
    float delta;

    int is_boundary = (r == 0) || (r == row - 1) || (c == 0) || (c == col - 1);

    if (is_boundary) {
        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] - current_temp) * Rx_1 +
                (temp_in[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r == 0 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - current_temp) * Rx_1 +
                (temp_in[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r == row - 1 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx - 1] - current_temp) * Rx_1 +
                (temp_in[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r == row - 1 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] - current_temp) * Rx_1 +
                (temp_in[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * current_temp) * Rx_1 +
                (temp_in[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + col] + temp_in[idx - col] - 2.0f * current_temp) * Ry_1 +
                (temp_in[idx - 1] - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (r == row - 1) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * current_temp) * Rx_1 +
                (temp_in[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        } else if (c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp_in[idx + col] + temp_in[idx - col] - 2.0f * current_temp) * Ry_1 +
                (temp_in[idx + 1] - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }
    } else {
        delta = Cap_1 * (power[idx] +
            (temp_in[idx + col] + temp_in[idx - col] - 2.0f * current_temp) * Ry_1 +
            (temp_in[idx + 1] + temp_in[idx - 1] - 2.0f * current_temp) * Rx_1 +
            (amb_temp - current_temp) * Rz_1);
    }

    temp_out[idx] = current_temp + delta;
}
